import{_ as e,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G11_前十大客戶與供應商穩定度_投資研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G11_前十大客戶與供應商穩定度_投資研究員.md"}'),l={name:"審計報告庫/經營審計/3189_景碩/20260423/G11_前十大客戶與供應商穩定度_投資研究員.md"};function i(_,a,d,c,n,h){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="g11-前十大客戶與供應商穩定度-投資研究員-審計報告" tabindex="-1">G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告 <a class="header-anchor" href="#g11-前十大客戶與供應商穩定度-投資研究員-審計報告" aria-label="Permalink to &quot;G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩前十大客戶集中度超過70%，前三大客戶（NVIDIA、Broadcom、AMD/Xilinx）約佔45-55%。供應商穩定度高——前三大原料供應商（味之素ABF膜、長春化工BT樹脂、三井金屬銅箔）均為長期合作夥伴，平均合作年資&gt;10年。供應端風險來自味之素的ABF膜單一壟斷，以量控價能力強。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B（持平）。客戶集中度高是載板產業結構性特徵，短期無法改變。供應鏈穩定度良好但ABF膜單一供應商風險存在。2025-2026年ABF載板持續供需吃緊，景碩對上游議價權偏弱但對下游（NVIDIA等）有漲價空間。前三大客戶佔營收約50%，客戶多樣性待提升。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>前十大客戶佔比推估（依業界公開數據估算）：(1) NVIDIA 25-30%（GPU載板）(2) Broadcom 10-15%（網通晶片+ASIC）(3) AMD/Xilinx 8-12%（FPGA+GPU載板）(4) Qualcomm 8-10%（車用Snapdragon）(5) Google 5-8%（TPU載板）(6) Micron 3-5%（BT載板DDR5）(7) MediaTek 3-5%（手機SoC）(8-10) TI+其他半導體IDM+華碩集團約5-10%。值得注意的是，前三大客戶貢獻約50%營收，客戶擴散度偏低。</p><p>供應商穩定度分析：味之素ABF膜供應量在2023-2025年間基本持平（年增5-8%，來自良率提升非產能擴張），景碩透過長期合約鎖定了基本配額，供應穩定性中等偏上。長春化工BT樹脂供貨穩定，年供應量成長15-20%配合BT載板業務擴張。三井金屬銅箔供應充足（載板佔銅箔終端用量僅約8%）。</p><p>供應商依賴度特徵：一級關鍵材料（ABF膜）一家獨大；二級材料（BT樹脂、銅箔）多源供應；輔料（藥水、靶材等）競爭充分。最穩定的供應關係是BT樹脂（長春化工為台灣在地供應，交期短且品質穩定）。最脆弱的供應關係是ABF膜（日本一線供應、地震/海運風險受制於日本物流穩定度）。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>客戶集中度是雙面刃：高集中度代表高依賴度，但也象徵景碩已被全球頂級客戶認證為合格供應商。NVIDIA不輕易更換載板供應商（單一供應商認證週期12-18個月），短期內存量供應關係穩固。真正風險在於：若NVIDIA決定縮減供應商數量或調整產品路線（如自行設計載板），景碩的營收將出現斷層。</p><p>供應商端的ABF膜限制是行業性問題，短期內對所有載板製造商一視同仁。若味之素在2027年前啟動新產能擴充計劃，將解除載板產業最大的供給瓶頸。</p><p>建議監測指標：(1)NVIDIA佔景碩營收佔比的季度變化（理想是隨ASIC客戶成長而逐漸降至&lt;20%）(2)味之素資本支出計劃公告（如有新廠計劃為正面訊號）(3)景碩是否開始測試ABF膜替代材料（目前無公開資訊）。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>法說會</code>: 景碩客戶結構（NVIDIA為最大客戶）</li><li><code>優分析UAnalyze</code>: 前十大客戶佔比推估（&gt;70%）</li><li><code>經濟日報</code>: NVIDIA GPU載板供應鏈報導</li><li><code>IEK產業情報網</code>: ABF膜供應鏈限制（味之素95%全球市佔）</li><li><code>工研院產業經濟與趨勢研究中心(IEK)</code>: 載板原料供應商分析</li></ul>',17)])])}const A=e(l,[["render",i]]);export{p as __pageData,A as default};
